public class Main {
    public static void main(String[] args) {
        int[] nums = {1, 2, 3, 4, 5};

        // Standard for loop
        int sum = 0;
        for (int i = 0; i < nums.length; i++) {
            sum += nums[i];
        }
        System.out.println(sum);  // 15

        // Enhanced for-each
        int max = nums[0];
        for (int n : nums) {
            if (n > max) max = n;
        }
        System.out.println(max);  // 5
    }
}

